 using Microsoft.VisualStudio.TestTools.UnitTesting;
 using Contoso.Pricing;

 namespace Contoso.Pricing.Tests;

 [TestClass]
 public sealed class PriceCalculatorTests
 {
     private readonly PriceCalculator _calculator = new();

     // ──────────────────────────────────────────────
     // CalculateTotal – happy-path (DataRow)
     // ──────────────────────────────────────────────

     [TestMethod]
     [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
     [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
     [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
     [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
     [DataRow(0.00, 5, 0.20, 0.00, DisplayName = "Zero price")]
     [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
     [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "Max tax rate (100%)")]
     public void CalculateTotal_WithValidInputs_ReturnsExpected(
         double unitPrice, int quantity, double taxRate, double expected)
     {
         var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

         Assert.AreEqual((decimal)expected, result);
     }

     // ──────────────────────────────────────────────
     // CalculateTotal – invalid inputs (DataRow)
     // ──────────────────────────────────────────────

     [TestMethod]
     [DataRow(-1.00, 1, 0.10, "unitPrice", DisplayName = "Negative unit price")]
     [DataRow(10.00, -1, 0.10, "quantity", DisplayName = "Negative quantity")]
     [DataRow(10.00, 1, -0.01, "taxRate", DisplayName = "Tax rate below 0")]
     [DataRow(10.00, 1, 1.01, "taxRate", DisplayName = "Tax rate above 1")]
     public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRange(
         double unitPrice, int quantity, double taxRate, string expectedParam)
     {
         var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
             () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

         Assert.AreEqual(expectedParam, ex.ParamName);
     }

     // ──────────────────────────────────────────────
     // ApplyDiscount – happy-path (DynamicData + ValueTuples)
     // ──────────────────────────────────────────────

     [TestMethod]
     [DynamicData(nameof(ApplyDiscountTestData))]
     public void ApplyDiscount_WithValidInputs_ReturnsExpected(
         decimal price, decimal discountPercent, decimal expected)
     {
         var result = _calculator.ApplyDiscount(price, discountPercent);

         Assert.AreEqual(expected, result);
     }

     public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> ApplyDiscountTestData =>
     [
         (100m, 0m, 100m),       // No discount
         (100m, 10m, 90m),       // 10% off
         (100m, 50m, 50m),       // Half price
         (100m, 100m, 0m),       // Free
         (200m, 25m, 150m),      // 25% off $200
         (0m, 50m, 0m),          // Zero price
         (79.99m, 15m, 67.9915m) // Fractional result
     ];

     // ──────────────────────────────────────────────
     // ApplyDiscount – invalid discount (DynamicData)
     // ──────────────────────────────────────────────

     [TestMethod]
     [DynamicData(nameof(InvalidDiscountTestData))]
     public void ApplyDiscount_WithInvalidDiscount_ThrowsArgumentOutOfRange(
         decimal price, decimal discountPercent)
     {
         var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
             () => _calculator.ApplyDiscount(price, discountPercent));

         Assert.AreEqual("discountPercent", ex.ParamName);
     }

     public static IEnumerable<(decimal price, decimal discountPercent)> InvalidDiscountTestData =>
     [
         (100m, -1m),    // Below zero
         (100m, 100.01m) // Above 100
     ];

     // ──────────────────────────────────────────────
     // FormatPrice (DataRow)
     // ──────────────────────────────────────────────

     [TestMethod]
     [DataRow(19.99, "$", "$19.99", DisplayName = "Default symbol")]
     [DataRow(5.5, "€", "€5.50", DisplayName = "Euro symbol")]
     [DataRow(0.0, "$", "$0.00", DisplayName = "Zero price")]
     [DataRow(1234.1, "£", "£1234.10", DisplayName = "Pound, padded decimals")]
     public void FormatPrice_WithCurrencySymbol_ReturnsFormattedString(
         double price, string symbol, string expected)
     {
         var result = _calculator.FormatPrice((decimal)price, symbol);

         Assert.AreEqual(expected, result);
     }

     [TestMethod]
     public void FormatPrice_WithDefaultSymbol_UsesDollarSign()
     {
         var result = _calculator.FormatPrice(42.00m);

         Assert.AreEqual("$42.00", result);
     }
 }

